create table dirkspzm32.rs232_client_cfg (
    sid           varchar2(2 char) default '01' not null enable,
    firma_nr      number(6, 0) default 1 not null enable,
    hostname      varchar2(150 char) not null enable,
    app_exename   varchar2(150 char) not null enable,
    instance_id   number(*, 0) default 1 not null enable,
    comport       varchar2(20 char) default 'COM1' not null enable,
    baudrate      number(*, 0) default 9600 not null enable,
    databits      number(*, 0) default 8 not null enable,
    parity        varchar2(20 char) default 'none' not null enable,
    stopbits      number(*, 0) default 1 not null enable,
    flowcontrol   varchar2(20 char) default 'none' not null enable,
    src_protocol  varchar2(20 char) default 'PFX/SFX' not null enable,
    src_pfxchar   number(*, 5) default 2,
    src_sfxchar   number(*, 5) default 3,
    response_req  varchar2(1 char) default 'F' not null enable,
    dest_mode     varchar2(20 char) default 'local' not null enable,
    dest_protocol varchar2(20 char) default 'PFX/SFX',
    dest_mt       number(*, 5) default - 1,
    dest_mc       number(*, 5) default - 1,
    dest_host     varchar2(150 char) default 'localhost',
    dest_port     number(*, 0) default 8000,
    dest_pfxchar  number(*, 0) default 2,
    dest_sfxchar  number(*, 0) default 3,
    enabled       varchar2(1 char) default 'F' not null enable
);

alter table dirkspzm32.rs232_client_cfg
    add constraint pk_rs232_client_cfg
        primary key ( sid,
                      firma_nr,
                      hostname,
                      app_exename,
                      instance_id,
                      comport )
            using index enable;


